mapper.select:
SELECT m.*, u.nickname AS sender_name, u.avatar AS sender_avatar FROM message m INNER JOIN conversation_member cm ON cm.conversation_id = m.conversation_id AND cm.user_id = #{userId} AND cm.deleted = 0 LEFT JOIN message_hidden mh ON mh.message_id = m.id AND mh.user_id = #{userId} AND mh.deleted = 0 LEFT JOIN user u ON u.id = m.sender_id WHERE m.conversation_id = #{conversationId} AND m.deleted = 0 AND mh.id IS NULL AND m.created_at >= cm.created_at
AND m.id < #{lastId}
ORDER BY m.id DESC LIMIT #{size}

SELECT COUNT(1) FROM message
WHERE conversation_id = #{conversationId}
  AND sender_id != #{userId}
  AND deleted = 0
  AND created_at > #{lastReadAt}
